// Home.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Home.css';

const Home = () => {
  const [recentMaterials, setRecentMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchRecentMaterials();
  }, []);

  const fetchRecentMaterials = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/materials/recent');
      const data = await response.json();
      
      if (data.success) {
        setRecentMaterials(data.materials);
      }
    } catch (error) {
      console.error('Error fetching recent materials:', error);
    } finally {
      setLoading(false);
    }
  };

  const getMaterialTypeInfo = (type) => {
    switch (type?.toLowerCase()) {
      case 'notes':
        return { icon: '📄', label: 'NOTES', bg: '#dbeafe', color: '#1d4ed8' };
      case 'pyq':
        return { icon: '📝', label: 'PYQ', bg: '#fef3c7', color: '#92400e' };
      case 'syllabus':
        return { icon: '📋', label: 'SYLLABUS', bg: '#dcfce7', color: '#166534' };
      case 'imp_questions':
        return { icon: '❓', label: 'IMP QUES', bg: '#f3e8ff', color: '#6b21a8' };
      default:
        return { icon: '📄', label: 'MATERIAL', bg: '#f1f5f9', color: '#475569' };
    }
  };

  const handleViewAll = () => {
    navigate('/all-materials');
  };

  const handleDownload = (materialId) => {
    // Download functionality
    console.log('Downloading:', materialId);
    navigate('/all-materials');
  };

  if (loading) {
    return <div className="home-loading">Loading...</div>;
  }

  return (
    <div className="home-container">
      {/* Hero Section */}
      <section className="hero-section">
        <h1>Welcome to Study Portal</h1>
        <p>Your one-stop destination for all study materials</p>
      </section>

      {/* Recent Materials Section */}
      <section className="recent-materials-section">
        <div className="section-header">
          <h2>📚 Latest Study Materials</h2>
          <button onClick={handleViewAll} className="view-all-btn">
            View All →
          </button>
        </div>

        {recentMaterials.length === 0 ? (
          <p className="no-materials">No materials available yet.</p>
        ) : (
          <div className="materials-grid">
            {recentMaterials.map((material) => {
              const typeInfo = getMaterialTypeInfo(material.type);
              
              return (
                <div key={material.id} className="material-card">
                  {/* ✅ Title with type icon */}
                  <h3 className="material-title">
                    {typeInfo.icon} {material.title}
                  </h3>
                  
                  {/* ✅ Details Column - Course, Person, Date, aur BADGE date ke niche */}
                  <div className="material-details">
                    <div className="detail-item">
                      <span className="detail-icon">📚</span>
                      <span className="detail-text">{material.course || 'N/A'}</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-icon">👤</span>
                      <span className="detail-text">{material.user_name || 'Unknown'}</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-icon">📅</span>
                      <span className="detail-text">
                        {material.uploaded_at ? new Date(material.uploaded_at).toLocaleDateString() : 'N/A'}
                      </span>
                    </div>
                    
                    {/* ✅ BADGE - Date ke niche same column mein */}
                    <div className="detail-item badge-detail-item">
                      <span className="detail-icon">{typeInfo.icon}</span>
                      <span 
                        className="detail-badge"
                        style={{ 
                          background: typeInfo.bg,
                          color: typeInfo.color
                        }}
                      >
                        {typeInfo.label}
                      </span>
                    </div>
                  </div>

                  {/* ✅ Stats - Views aur Downloads ek line mein */}
                  <div className="material-stats">
                    <div className="stat-item">
                      <span className="stat-icon">👁️</span>
                      <span className="stat-number">{material.views || 0}</span>
                    </div>
                    <div className="stat-item">
                      <span className="stat-icon">⬇️</span>
                      <span className="stat-number">{material.downloads || 0}</span>
                    </div>
                  </div>

                  {/* ✅ Download Button */}
                  <button 
                    className="download-btn-home"
                    onClick={() => handleDownload(material.id)}
                  >
                    ⬇️ Download
                  </button>
                </div>
              );
            })}
          </div>
        )}
      </section>
    </div>
  );
};

export default Home;
